// src/workers/ingestion/consumer.ts
async function handleIngestionBatch(batch, env3, ctx) {
  const results = await Promise.allSettled(
    batch.messages.map((msg) => processIngestionMessage(msg, env3, ctx))
  );
  const failures = results.filter((r2) => r2.status === "rejected");
  if (failures.length > 0 && failures.length === batch.messages.length) {
    throw new Error(`All ${failures.length} ingestion messages failed`);
  }
}
__name(handleIngestionBatch, "handleIngestionBatch");
async function processIngestionMessage(msg, env3, ctx) {
  const { type, tenantId, payload } = msg.body;
  const doId = env3.MCPAGENT.idFromName(tenantId);
  const stub = env3.MCPAGENT.get(doId);
  let tmk = null;
  try {
    tmk = await stub.getTmk();
  } catch {
    tmk = null;
  }
  if (!tmk) {
    msg.retry({ delaySeconds: 30 });
    return;
  }
  switch (type) {
    case "sms_inbound":
      await handleSmsInbound(tenantId, payload, tmk, env3, ctx);
      break;
    case "gmail_thread":
      await handleGmailThread(tenantId, payload, tmk, env3, ctx);
      break;
    case "calendar_event":
      await handleCalendarEvent(tenantId, payload, tmk, env3, ctx);
      break;
    case "obsidian_note":
      await handleObsidianNote(tenantId, payload, tmk, env3, ctx);
      break;
    case "bootstrap_gmail_thread":
      await handleBootstrapGmailThread(tenantId, payload, tmk, env3, ctx);
      break;
    case "bootstrap_calendar_event":
      await handleBootstrapCalendarEvent(tenantId, payload, tmk, env3, ctx);
      break;
    case "bootstrap_drive_file":
      await handleBootstrapDriveFile(tenantId, payload, tmk, env3, ctx);
      break;
    default:
      break;
  }
  msg.ack();
}
__name(processIngestionMessage, "processIngestionMessage");

