async function handleObsidianPoll(event, env3, ctx) {
  const tenants = await env3.D1_US.prepare(
    `SELECT id FROM tenants WHERE obsidian_sync_enabled = 1`
  ).all();
  if (!tenants.results?.length) return;
  for (const tenant of tenants.results) {
    const lastPollKey = `obsidian_last_poll:${tenant.id}`;
    const lastPoll = await env3.KV_SESSION.get(lastPollKey);
    const lastPollMs = lastPoll ? parseInt(lastPoll, 10) : 0;
    if (event.cron === "*/1 * * * *" && Date.now() - lastPollMs < 55e3) continue;
    const message = {
      type: "obsidian_note",
      tenantId: tenant.id,
      payload: {
        pollType: event.cron === "*/1 * * * *" ? "folder" : "vault_scan",
        sinceMs: lastPollMs
      },
      enqueuedAt: Date.now()
    };
    ctx.waitUntil(env3.QUEUE_NORMAL.send(message));
    ctx.waitUntil(env3.KV_SESSION.put(lastPollKey, String(Date.now())));
  }
}
__name(handleObsidianPoll, "handleObsidianPoll");

