async function fetchAndValidateKek(tenantId, env3) {
  const tenant = await env3.D1_US.prepare(
    "SELECT cron_kek_expires_at FROM tenants WHERE id = ?"
  ).bind(tenantId).first();
  if (!tenant?.cron_kek_expires_at || tenant.cron_kek_expires_at < Date.now()) {
    await writeDeferredAnomaly(tenantId, env3);
    return null;
  }
  const rawB64 = await env3.KV_SESSION.get(`cron_kek:${tenantId}`);
  if (!rawB64) {
    await writeDeferredAnomaly(tenantId, env3);
    return null;
  }
  const rawBytes = Uint8Array.from(atob(rawB64), (c) => c.charCodeAt(0));
  return crypto.subtle.importKey(
    "raw",
    rawBytes,
    { name: "AES-GCM" },
    false,
    ["encrypt", "decrypt"]
  );
}
